INSERT INTO TB_UPLD_FILE (
    UPLD_FILE_CD
  , FILE_SEQ
  , FILE_NM
  , SAVE_FILE_NM
  , SAVE_PATH
  , FILE_SIZ
  , FILE_EXTN
  , UPLD_DTM
  , USE_YN
  , DEL_YN
  , CRE_USR_CD
  , CRE_DTM
  , UPD_USR_CD
  , UPD_DTM
) VALUES (
    #{upldFileCd}
  , #{fileSeq}
  , #{fileNm}
  , #{saveFileNm}
  , #{savePath}
  , #{fileSiz}
  , #{fileExtn}
  , DATE_FORMAT(NOW(), '%Y%m%d%H%i%s')
  , #{useYn}
  , #{delYn}
  , #{ssnUsrCd}
  , SYSDATE()
  , #{ssnUsrCd}
  , SYSDATE()
)

mapper.delete:
